using Ledgerly.Application.Accounts; using Ledgerly.Application.Bills; using Ledgerly.Application.Contacts; using Ledgerly.Application.Expenses; using Ledgerly.Application.Invoices; using Ledgerly.Application.Journals; using Microsoft.Extensions.DependencyInjection; namespace Ledgerly.Application; public static class DependencyInjection { public static IServiceCollection AddApplication(this IServiceCollection services){ services.AddScoped<AccountService>(); services.AddScoped<JournalService>(); services.AddScoped<ContactService>(); services.AddScoped<InvoiceService>(); services.AddScoped<BillService>(); services.AddScoped<ExpenseService>(); return services; } }
